# Tests for Step 5: RequestRouter
assert 'RequestRouter' in dir(), 'RequestRouter class must be defined'

router = RequestRouter()

# Test route decorator registers handlers
@router.route('ping')
def handle_ping(args):
    return 'pong'

@router.route('echo')
def handle_echo(args):
    return ' '.join(args)

@router.route('add')
def handle_add(args):
    return sum(int(a) for a in args)

# Test dispatch with no arguments
assert callable(getattr(router, 'dispatch', None)), 'RequestRouter must have dispatch method'
assert callable(getattr(router, 'route', None)), 'RequestRouter must have route method'

result = router.dispatch('ping')
assert result == 'pong', f'dispatch("ping") should return "pong", got {result}'

# Test dispatch with arguments
result = router.dispatch('echo hello world')
assert result == 'hello world', f'dispatch("echo hello world") should return "hello world", got {result}'

# Test dispatch with numeric arguments
result = router.dispatch('add 1 2 3')
assert result == 6, f'dispatch("add 1 2 3") should return 6, got {result}'

# Test dispatch with unknown command raises ValueError
try:
    router.dispatch('unknown_command')
    assert False, 'dispatch should raise ValueError for unknown commands'
except ValueError:
    pass

# Test that route decorator returns the original function
@router.route('test')
def handle_test(args):
    return 'ok'
assert callable(handle_test), 'route decorator should return the original function'
